"""HTTP client module using requests with retry support."""

import requests
from urllib3.util.retry import Retry
from requests.adapters import HTTPAdapter


class APIClient:
    """Simple API client with automatic retries."""

    def __init__(self, base_url: str, max_retries: int = 3):
        self.base_url = base_url.rstrip("/")
        self.session = requests.Session()
        retry_strategy = Retry(
            total=max_retries,
            backoff_factor=0.5,
            status_forcelist=[429, 500, 502, 503, 504],
        )
        adapter = HTTPAdapter(max_retries=retry_strategy)
        self.session.mount("https://", adapter)
        self.session.mount("http://", adapter)

    def get(self, endpoint: str, **kwargs) -> requests.Response:
        """Make a GET request to the given endpoint."""
        url = f"{self.base_url}/{endpoint.lstrip('/')}"
        return self.session.get(url, **kwargs)

    def post(self, endpoint: str, data=None, json=None, **kwargs) -> requests.Response:
        """Make a POST request to the given endpoint."""
        url = f"{self.base_url}/{endpoint.lstrip('/')}"
        return self.session.post(url, data=data, json=json, **kwargs)

    @property
    def versions(self) -> dict:
        """Return version info for key dependencies."""
        import urllib3
        return {
            "requests": requests.__version__,
            "urllib3": urllib3.__version__,
        }
